  "active": null,
  "currentMode": "work",
  "workMin": 25,
  "breakMin": 5,
  "history": [
    {
      "id": "ab12",
      "date": "2026-05-23",
      "start": "09:00",
      "end": "09:25",
      "focusMin": 25,
      "completed": true
    }
  ]
